/**
 * @brief Solves the maximum score problem for a strictly alternating subsequence with minimum distance constraint.
 *
 * @param nums The input array of integers.
 * @param k The minimum required distance between consecutive indices.
 * @return The maximum possible score.
 */
int64 solve(vector<int64> nums, int64 k) {
    int n = nums.size();
    if (n == 0) {
        return 0;
    }

    // DP state:
    // dp_up[i]: Maximum score of a valid subsequence ending at index i,
    //           where nums[i] is greater than the previous element (i.e., ... < nums[i]).
    // dp_down[i]: Maximum score of a valid subsequence ending at index i,
    //              where nums[i] is smaller than the previous element (i.e., ... > nums[i]).

    // Initialize DP arrays. A single element subsequence is always valid.
    vector<int64> dp_up(n);
    vector<int64> dp_down(n);

    for (int i = 0; i < n; ++i) {
        // Base case: subsequence of length 1, score is just nums[i].
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        // Check previous elements j such that i - j >= k
        for (int j = 0; j < i - k + 1; ++j) {
            // Transition for dp_up[i] (ending in '<' pattern, so previous must be '<' in the pattern)
            // We need a subsequence ending at j such that nums[j] < nums[i] (i.e., dp_down[j])
            // The previous pattern must have been '... > nums[j]' or it was the start.
            // If it was the start, it's covered by the base case.
            // If we extend a subsequence ending in dp_down[j] (i.e., ... > nums[j]), and nums[i] > nums[j],
            // the pattern becomes ... > nums[j] < nums[i]. This is an UP transition.
            if (nums[i] > nums[j]) {
                dp_up[i] = max(dp_up[i], dp_down[j] + nums[i]);
            }

            // Transition for dp_down[i] (ending in '>' pattern, so previous must be '>' in the pattern)
            // We need a subsequence ending at j such that nums[j] > nums[i] (i.e., dp_up[j])
            // If we extend a subsequence ending in dp_up[j] (i.e., ... < nums[j]), and nums[i] < nums[j],
            // the pattern becomes ... < nums[j] > nums[i]. This is a DOWN transition.
            if (nums[i] < nums[j]) {
                dp_down[i] = max(dp_down[i], dp_up[j] + nums[i]);
            }
        }
    }

    // The result is the maximum value found in either dp_up or dp_down
    int64 max_score = 0;
    for (int i = 0; i < n; ++i) {
        max_score = max({max_score, dp_up[i], dp_down[i]});
